package abiPythOracle

import (
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/tonkeeper/tongo/boc"
	"github.com/tonkeeper/tongo/tlb"
)

func TestExample(t *testing.T) {
	// https://tonviewer.com/transaction/91e2da6de76a7d0ff7b687dfba93af384578b722fc7ccc1877c9c2508ad46b10

	bocData := ""
	var inMsg ParsePriceFeedUpdatesMessage
	assert.NoError(t, unmarshall(&inMsg, bocData))

	assert.Equal(t, tlb.Uint64(1774538333), inMsg.MinPublishTime)
	assert.Equal(t, tlb.Uint64(1774538533), inMsg.MaxPublishTime)
	assert.Len(t, *inMsg.PriceIds.Value, 1)

	bocData = ""
	var outMsg OracleResponseSuccess
	assert.NoError(t, unmarshall(&outMsg, bocData))
	assert.Equal(t, (*inMsg.PriceIds.Value)[0], outMsg.PriceFeedsCell.Value.AssetID)
	assert.Equal(t, inMsg.CustomPayload, outMsg.AfterOperation)
}

func unmarshall[T tlb.UnmarshalerTLB](target T, bocData string) error {
	cells, err := boc.DeserializeBocHex(bocData)
	if err != nil {
		return err
	}
	return target.UnmarshalTLB(cells[0], tlb.NewDecoder())
}
